const data = $input.first().json;
const summary = data.error_summary || data.root_cause || 'CI/CD pipeline failure detected by Aeon';
return [{
  json: {
    routing_key: '{{ $credentials.pagerdutyIntegrationKey }}',
    event_action: 'trigger',
    dedup_key: `aeon-${data.pipeline || data.name}-${data.branch}`,
    payload: {
      summary: `[Aeon] ${data.pipeline || data.name} FAILED on ${data.branch}: ${summary.substring(0, 200)}`,
      severity: data.confidence >= 90 ? 'critical' : 'error',
      source: data.source || 'aeon',
      component: data.pipeline || data.name,
      group: 'ci-cd',
      class: 'build_failure',
      custom_details: {
        branch: data.branch,
        confidence: `${data.confidence}%`,
        build_url: data.url,
        root_cause: summary,
        aeon_dashboard: 'http://localhost:3000/incidents'
      }
    },
    links: [
      { href: data.url || '', text: 'View Build' },
      { href: 'http://localhost:3000/incidents', text: 'View in Aeon' }
    ]
  }
}];
